					</div>
					<div className="col-md-4 col-4 text-right">
						<a href="https://www.bakoremagic.com " target="_blank">
							<img  src="bakore_logo2.png" className="img-fluid" width="100"/>
						</a>
					</div>
				</div>
			</div>
		</footer>
